int solve_correct(int n, int m, int l, const vector<int>& a) {
    int low = 0, high = l;
    int ans = l;

    while (low <= high) {
        int mid = low + (high - low) / 2;
        bool possible = true;

        function<bool(int, vector<int>)> check = 
            [&](int time, vector<int> danger) {
            if (time > l) {
                for (int d : danger) {
                    if (d > mid) return false;
                }
                return true;
            }

            int flash_index = -1;
            for (int i = 0; i < n; ++i) {
                if (a[i] == time) {
                    flash_index = i;
                    break;
                }
            }

            if (flash_index != -1) {
                for (int j = 0; j < m; ++j) {
                    vector<int> next_danger = danger;
                    next_danger[j] = 0;
                    if (!check(time + 1, next_danger)) return false;
                }
                return true;
            } else {
                int worst_bot = 0;
                for(int i = 1; i < m; ++i){
                    if(danger[i] > danger[worst_bot]){
                        worst_bot = i;
                    }
                }
                danger[worst_bot]++;
                return check(time + 1, danger);
            }
        };

        if (check(1, vector<int>(m, 0))) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}

