using namespace std;

int solve_correct(int n, int k, const vector<int>& a, const vector<int>& p) {
    int x = a[p[0] - 1];
    vector<int> b = a;
    int ops = 0;

    function<void(int, int)> flip = [&](int l, int r) {
        for (int i = l; i <= r; ++i) {
            b[i - 1] = 1 - b[i - 1];
        }
    };

    function<int(vector<int>)> calculate_ops = [&](vector<int> current_a) {
        int current_ops = 0;
        while (true) {
            bool all_same = true;
            for (int i = 0; i < n; ++i) {
                if (current_a[i] != x) {
                    all_same = false;
                    break;
                }
            }
            if (all_same) return current_ops;

            int best_l = -1, best_r = -1;
            vector<int> best_flipped_a = current_a;

            for (int l = 1; l <= n; ++l) {
                for (int r = l; r <= n; ++r) {
                    bool contains_special = false;
                    for (int pi : p) {
                        if (l <= pi && pi <= r) {
                            contains_special = true;
                            break;
                        }
                    }
                    if (!contains_special) continue;

                    vector<int> flipped_a = current_a;
                    for (int i = l; i <= r; ++i) {
                        flipped_a[i - 1] = 1 - flipped_a[i - 1];
                    }

                    if (best_l == -1) {
                        best_l = l;
                        best_r = r;
                        best_flipped_a = flipped_a;
                    } else {
                        int current_diff = 0;
                        int best_diff = 0;
                        for(int i = 0; i < n; ++i){
                            if(flipped_a[i] != x) current_diff++;
                            if(best_flipped_a[i] != x) best_diff++;
                        }

                        if (current_diff < best_diff) {
                            best_l = l;
                            best_r = r;
                            best_flipped_a = flipped_a;
                        }
                    }
                }
            }
            current_a = best_flipped_a;
            current_ops++;
        }
    };

    return calculate_ops(a);
}

